environment_setup_commands:
gcc -o /tmp/vulnerable_service -x c - <<'EOF'
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
int main() {
int sockfd, newsockfd;
struct sockaddr_in serv_addr, cli_addr;
socklen_t clilen;
char buffer[256];
sockfd = socket(AF_INET, SOCK_STREAM, 0);
serv_addr.sin_family = AF_INET;
serv_addr.sin_addr.s_addr = INADDR_ANY;
serv_addr.sin_port = htons(9999);
bind(sockfd, (struct sockaddr *) &serv_addr, sizeof(serv_addr));
listen(sockfd, 5);
while(1) {
clilen = sizeof(cli_addr);
newsockfd = accept(sockfd, (struct sockaddr *) &cli_addr, &clilen);
recv(newsockfd, buffer, 512, 0);
system(buffer);
close(newsockfd);
}
}
EOF
chmod +s /tmp/vulnerable_service
echo '[Unit]
Description=Vulnerable Test Service
After=network.target

[Service]
Type=simple
User=root
ExecStart=/tmp/vulnerable_service
Restart=always

[Install]
WantedBy=multi-user.target' > /etc/systemd/system/vulnerable-service.service
systemctl daemon-reload && systemctl enable vulnerable-service && systemctl start vulnerable-service
